#nullable enable // autogenerated

using MVZ2.Vanilla.Audios;
using MVZ2Logic;
using MVZ2Logic.Entities;
using MVZ2Logic.Definitions;
using MVZ2Logic.Callbacks;
using MVZ2Logic.Definitions;
using MVZ2Logic.HeldItems;
using MVZ2Logic.Inputs;
using MVZ2Logic.Level;
using PVZEngine.Callbacks;

namespace MVZ2.GameContent.HeldItems
{
    [AutoHeldItemBehaviourDefinition(VanillaHeldItemBehaviourNames.rightMouseCancel)]
    public class RightMouseCancelHeldItemBehaviour : HeldItemBehaviourDefinition
    {
        public RightMouseCancelHeldItemBehaviour(string nsp, string name) : base(nsp, name)
        {
            AddTrigger(LogicCallbacks.POST_POINTER_ACTION, PostPointerActionCallback, filter: PointerPhase.Press);
        }
        private void PostPointerActionCallback(LogicCallbacks.PostPointerActionParams param, CallbackResult result)
        {
            var type = param.type;
            var button = param.button;
            if (type != PointerTypes.MOUSE || button != MouseButtons.RIGHT)
                return;
            var level = Global.Level.GetLevel();
            if (level == null || !level.IsGameRunning())
                return;
            var data = level.GetHeldItemData();
            var heldItemDef = data?.GetDefinition(level);
            if (data == null || heldItemDef == null)
                return;
            if (!heldItemDef.HasBehaviour(level, data, this))
                return;
            if (level.CancelHeldItem())
            {
                level.PlaySound(VanillaSoundID.tap);
            }
        }
    }
}
